local xml = require("xml")
local ngx = ngx

-- Main function to process the SOAP request
local function process_soap_request()
    -- 1. Read the request body
    ngx.req.read_body()
    local body_data = ngx.req.get_body_data()

    if not body_data then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Error: Request body is empty or not available.")
        return
    end

    -- 2. Validate Content-Type header (good practice for SOAP)
    local content_type = ngx.req.get_headers()["Content-Type"]
    if not content_type or (not content_type:match("text/xml") and not content_type:match("application/soap")) then
        ngx.status = ngx.HTTP_UNSUPPORTED_MEDIA_TYPE
        ngx.say("Error: Unsupported Content-Type. Expected text/xml or application/soap+xml.")
        ngx.log(ngx.ERR, "Unsupported Content-Type: ", content_type or "N/A")
        return
    end

    -- 3. Parse the XML from the request body
    -- 'lua-xml' handles standard XML entity references (&lt;, &gt;, &amp;, &quot;, &apos;)
    -- by expanding them into the text content. It does not load external DTDs,
    -- which enhances security against XXE vulnerabilities.
    local xml_doc, err = xml.parse(body_data)

    if not xml_doc then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Error parsing XML: ", err)
        ngx.log(ngx.ERR, "XML parsing failed: ", err, " Body: ", body_data)
        return
    end

    -- 4. Extract data from the parsed XML
    -- The 'lua-xml' library parses XML into a Lua table structure:
    --   - Element name: accessible via `_name` field (e.g., `xml_doc._name`).
    --   - Attributes: accessible via `_attr` table field (e.g., `xml_doc._attr.attributeName`).
    --   - Text content: accessible via `_text` field (e.g., `xml_doc.ChildElement._text`).
    --   - Child elements: accessible as direct keys on the parent table.
    --   - If multiple children have the same name, they are stored in an array at that key.
    --     e.g., `<Items><Item/><Item/></Items>` -> `xml_doc.Items.Item[1]`, `xml_doc.Items.Item[2]`

    local envelope = xml_doc
    -- Handle common SOAP Envelope namespaces
    if not envelope or (envelope._name ~= "Envelope" and envelope._name ~= "soap:Envelope" and envelope._name ~= "soapenv:Envelope") then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Invalid SOAP message: Root element is not an Envelope.")
        ngx.log(ngx.ERR, "Invalid SOAP root element: ", envelope._name or "N/A")
        return
    end

    local body = envelope.Body or envelope["soap:Body"] or envelope["soapenv:Body"]
    if not body then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Invalid SOAP message: No Body element found.")
        ngx.log(ngx.ERR, "No SOAP Body element found.")
        return
    end

    -- Attempt to find the main request element within the SOAP Body.
    -- This often assumes the first non-attribute child in the Body is the main request.
    local request_element
    for _, child_val in pairs(body) do
        -- Ensure it's a table representing an XML element and not the _attr special key
        if type(child_val) == "table" and child_val._name and child_val._name ~= "_attr" then
            request_element = child_val
            break -- Found the primary request element
        end
    end

    if not request_element then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Invalid SOAP message: No specific request element found in Body.")
        ngx.log(ngx.ERR, "No request element found in SOAP Body.")
        return
    end

    ngx.log(ngx.INFO, "SOAP Request received: Operation=", request_element._name)

    -- Example: Extracting specific data from a hypothetical request element
    -- For a SOAP request like:
    -- <soapenv:Envelope ...>
    --   <soapenv:Body>
    --     <ns:MyOperation xmlns:ns="http://example.com/api">
    --       <ns:InputParam>Hello &amp; World!</ns:InputParam>
    --       <ns:User id="123" type="admin"/>
    --       <ns:Details>
    --         <ns:Item name="Laptop" quantity="1"/>
    --         <ns:Item name="Mouse" quantity="2"/>
    --       </ns:Details>
    --     </ns:MyOperation>
    --   </soapenv:Body>
    -- </soapenv:Envelope>

    local operation_name = request_element._name -- e.g., "MyOperation"
    local input_param = request_element.InputParam and request_element.InputParam._text
    local user_id = request_element.User and request_element.User._attr and request_element.User._attr.id
    local user_type = request_element.User and request_element.User._attr and request_element.User._attr.type

    local item_list = {}
    local details_element = request_element.Details
    if details_element then
        local items = details_element.Item -- Can be a table for single, or an array of tables for multiple
        if items then
            if type(items) == "table" and items._name == "Item" then
                -- Single item case (lua-xml doesn't create array if only one)
                table.insert(item_list, {
                    name = items._attr and items._attr.name,
                    quantity = items._attr and items._attr.quantity
                })
            elseif type(items) == "table" then -- implies an array of items if items[1] exists
                -- Multiple items (lua-xml puts them in an array if names are same)
                for _, item_table in ipairs(items) do
                    table.insert(item_list, {
                        name = item_table._attr and item_table._attr.name,
                        quantity = item_table._attr and item_table._attr.quantity
                    })
                end
            end
        end
    end

    ngx.log(ngx.INFO, "Extracted Data for ", operation_name, ":")
    ngx.log(ngx.INFO, "  InputParam: ", input_param or "N/A")
    ngx.log(ngx.INFO, "  User ID: ", user_id or "N/A")
    ngx.log(ngx.INFO, "  User Type: ", user_type or "N/A")
    for i, item in ipairs(item_list) do
        ngx.log(ngx.INFO, "  Item ", i, ": Name=", item.name or "N/A", ", Quantity=", item.quantity or "N/A")
    end

    -- ---
    -- 5. Your business logic and processing would go here
    --    Based on 'operation_name' and extracted parameters.
    --    You might forward this to an upstream service, interact with a database, etc.
    --    For demonstration, we'll just return a success response.
    -- ---

    -- 6. Construct and send a SOAP response
    ngx.header["Content-Type"] = "text/xml; charset=utf-8"
    ngx.status = ngx.HTTP_OK

    local response_message = "Request for " .. operation_name .. " processed successfully."
    if input_param then
        -- Important: Escape special XML characters in text content for the response
        response_message = response_message .. " Input: '" .. ngx.escape_uri(input_param) .. "'"
    end

    local response_xml = [[<?xml version="1.0" encoding="utf-8"?>
<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/"
                  xmlns:xsd="http://www.w3.org/2001/XMLSchema"
                  xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance">
   <soapenv:Body>
      <ns:]] .. operation_name .. [[Response xmlns:ns="http://example.com/api">
         <ns:Status>Success</ns:Status>
         <ns:Message>]] .. response_message .. [[</ns:Message>
         <ns:ProcessedUser id="]] .. (user_id or "N/A") .. [[" type="]] .. (user_type or "N/A") .. [["/>
         <ns:ProcessedItemsCount>]] .. #item_list .. [[</ns:ProcessedItemsCount>
      </ns:]] .. operation_name .. [[Response>
   </soapenv:Body>
</soapenv:Envelope>]]

    ngx.say(response_xml)
end

-- Execute the request processing function
process_soap_request()